3	const isNeighbor = ([x1, y1]: Cell, [x2, y2]: Cell): boolean =>
4	  (x1 !== x2 || y1 !== y2) &&
5	  Math.abs(x1 - x2) <= 1 &&
6	  Math.abs(y1 - y2) <= 1;
7	
8	const countNeighbors = (cell: Cell, cells: Cell[]): number =>
9	  cells.filter((other) => isNeighbor(cell, other)).length;
10	
11	export function nextGeneration(cells: Cell[]): Cell[] {
12	  return cells.filter((cell) => countNeighbors(cell, cells) >= 2);
13	}
